#include <stdio.h>
int popcount_naive(unsigned int n) {
    int count = 0;
    while (n) { count += n & 1; n >>= 1; }
    return count;
}
int popcount_kernighan(unsigned int n) {
    int count = 0;
    while (n) { count++; n &= n - 1; }
    return count;
}
int main(void) {
    unsigned int v = 0xDEADBEEF;
    printf("0xDEADBEEF naive    : %d\n", popcount_naive(v));
    printf("0xDEADBEEF kernighan: %d\n", popcount_kernighan(v));
    printf("0x00000000 naive    : %d\n", popcount_naive(0));
    printf("0xFFFFFFFF kernighan: %d\n", popcount_kernighan(0xFFFFFFFF));
    return 0;
}

starter_code_stages:
#include <stdio.h>

// ★ Stage 0 — Exemple complet
int popcount_naive(unsigned int n) {
    int count = 0;
    while (n) {          // ★ tant que des bits à 1 restent
        count += n & 1;  // ★ teste le bit de poids faible
        n >>= 1;         // ★ décale vers la droite
    }
    return count;
}
int popcount_kernighan(unsigned int n) {
    int count = 0;
    while (n) {          // ★ O(k) : k = nombre de bits à 1
        count++;
        n &= n - 1;      // ★ efface le bit le plus bas à 1
    }
    return count;
}
int main(void) {
    unsigned int v = 0xDEADBEEF;
    printf("0xDEADBEEF naive    : %d\n", popcount_naive(v));     // 24
    printf("0xDEADBEEF kernighan: %d\n", popcount_kernighan(v)); // 24
    printf("0x00000000 naive    : %d\n", popcount_naive(0));      // 0
    printf("0xFFFFFFFF kernighan: %d\n", popcount_kernighan(0xFFFFFFFF)); // 32
    return 0;
}

